// Express webhook receiver with signature verification (Stripe-style)
import crypto from 'crypto';

app.post('/webhooks/stripe',
  express.raw({ type: 'application/json' }), // need the RAW body for HMAC
  (req, res) => {
    const sig = req.headers['stripe-signature'];
    const expected = crypto
      .createHmac('sha256', process.env.WEBHOOK_SECRET)
      .update(req.body)
      .digest('hex');

    // constant-time compare to prevent timing attacks
    if (!crypto.timingSafeEqual(Buffer.from(sig), Buffer.from(expected))) {
      return res.status(400).send('Invalid signature');
    }

    const event = JSON.parse(req.body);

    // Idempotency: skip if we've seen this event id before
    if (await alreadyProcessed(event.id)) return res.sendStatus(200);

    res.sendStatus(200);          // ACK fast...
    await queue.add(event);       // ...process asynchronously
  }
);

