  e.waitUntil(caches.keys().then(keys =>
    Promise.all(keys.filter(k => k !== CACHE).map(k => caches.delete(k)))));
});

// fetch: stale-while-revalidate for API GETs, cache-first for assets
self.addEventListener('fetch', (e) => {
  if (e.request.method !== 'GET') return;
  e.respondWith((async () => {
    const cached = await caches.match(e.request);
    const network = fetch(e.request).then(res => {
      caches.open(CACHE).then(c => c.put(e.request, res.clone()));
      return res;
    }).catch(() => cached);
    return cached || network; // serve cache fast, refresh in background
  })());
});

// Refresh-token flow with auto-retry on 401 (fetch wrapper)
let accessToken = null;

async function apiFetch(url, opts = {}, retried = false) {
  const res = await fetch(url, {
    ...opts,
    headers: { ...opts.headers, Authorization: `Bearer ${accessToken}` },
    credentials: 'include', // send the httpOnly refresh cookie
  });

  if (res.status === 401 && !retried) {
    // access token expired → use refresh cookie to mint a new one
    const r = await fetch('/auth/refresh', { method: 'POST', credentials: 'include' });
    if (!r.ok) { redirectToLogin(); throw new Error('Session expired'); }
    accessToken = (await r.json()).accessToken;
    return apiFetch(url, opts, true); // retry once
  }
  return res;
}

