export const handler = async (event) => {
  // event = HTTP request from API Gateway
  const { prompt } = JSON.parse(event.body);

  // (verify the caller's own auth token here)
  if (!isAuthorized(event.headers.authorization)) {
    return { statusCode: 401, body: 'Unauthorized' };
  }

  const r = await fetch('https://api.openai.com/v1/chat/completions', {
    method: 'POST',
    headers: { Authorization: `Bearer ${secret}` }, // secret stays server-side
    body: JSON.stringify({ model: 'gpt-4', messages: [{ role: 'user', content: prompt }] }),
  });

  return {
    statusCode: 200,
    headers: { 'content-type': 'application/json' },
    body: JSON.stringify(await r.json()),
  };
};

