// Stream an LLM response to the UI via your backend proxy (fetch streaming)
async function streamChat(prompt, onToken, signal) {
  const res = await fetch('/api/chat', {        // your proxy holds the secret
    method: 'POST',
    headers: { 'content-type': 'application/json' },
    body: JSON.stringify({ prompt }),
    signal,                                       // allow cancellation
  });

  const reader = res.body.getReader();
  const decoder = new TextDecoder();
  while (true) {
    const { value, done } = await reader.read();
    if (done) break;
    onToken(decoder.decode(value, { stream: true })); // render tokens as they arrive
  }
}

